/**
 * Log It — College Team Data
 * Auto-generated from ESPN API with conference assignments.
 * Teams are organized by conference for the filter bar UI.
 *
 * Logo URL pattern: https://a.espncdn.com/i/teamlogos/ncaa/500/{id}.png
 */

export interface CollegeTeam {
  name: string;
  short: string;
  id: string;
  abbrev: string;
  conference: string;
  logo: string;
}

function buildTeams(
  raw: { name: string; short: string; id: string; abbrev: string; conference: string }[]
): CollegeTeam[] {
  return raw.map(t => ({
    ...t,
    logo: `https://a.espncdn.com/i/teamlogos/ncaa/500/${t.id}.png`,
  }));
}

